import Anthropic from "@anthropic-ai/sdk";

// One-line food/drink guidance per medication, generated by Claude.
// Cached in memory so each drug name is only generated once per server run.
const cache = new Map();

const GUIDANCE_SCHEMA = {
  type: "object",
  properties: {
    note: {
      type: "string",
      description:
        "One plain-language sentence on how to take this medication with food or drink.",
    },
    fat_soluble: {
      type: "boolean",
      description: "True if the medication absorbs better with dietary fat.",
    },
  },
  required: ["note", "fat_soluble"],
  additionalProperties: false,
};

const SYSTEM_PROMPT =
  "You are a pharmacist writing one-line food and drink guidance for a " +
  "medication tracker app. Be accurate, practical, and brief — one sentence, " +
  "like: 'Fat-soluble — absorbs best with a meal that includes some fat.' or " +
  "'Take with food to reduce stomach upset; keep it 2 hours apart from calcium.' " +
  "If the given name is not a recognizable medication or supplement, the note " +
  "should say no guidance is available. This is general education, not medical advice.";

export const getMedGuidance = async (req, res) => {
  const { drug } = req.query;

  if (!drug || !drug.trim()) {
    return res.status(400).json({ message: "Drug name is required" });
  }

  if (!process.env.ANTHROPIC_API_KEY) {
    return res.status(503).json({
      message:
        "Guidance service not configured — set ANTHROPIC_API_KEY in the backend .env",
    });
  }

  const key = drug.trim().toLowerCase();
  if (cache.has(key)) {
    return res.json(cache.get(key));
  }

  try {
    const client = new Anthropic();
    const response = await client.messages.create({
      model: "claude-opus-4-8",
      max_tokens: 1000,
      thinking: { type: "adaptive" },
      output_config: {
        effort: "low",
        format: { type: "json_schema", schema: GUIDANCE_SCHEMA },
      },
      system: SYSTEM_PROMPT,
      messages: [{ role: "user", content: `Medication: ${drug.trim()}` }],
    });

    if (response.stop_reason === "refusal") {
      return res
        .status(422)
        .json({ message: "No guidance available for this medication" });
    }

    const text =
      response.content.find((block) => block.type === "text")?.text || "{}";
    const guidance = JSON.parse(text);

    cache.set(key, guidance);
    res.json(guidance);
  } catch (error) {
    console.error("Error generating medication guidance:", error.message);
    res.status(500).json({ message: "Failed to generate guidance" });
  }
};
